+const std = @import("std");
+const llama = @import("llama.zig");
+const logger = @import("logger.zig");
+
+// =============================================================================
+// Dream Validation: Post-Training Sanity Check System
+// =============================================================================
+// Validates LoRA adapters after training but before activation, preventing
+// "nightmare" adapters from lobotomizing the model.
+
+/// Configuration for the validation system
+pub const ValidationConfig = struct {
+    /// Enable/disable validation (for testing or emergency bypass)
+    enabled: bool = true,
+    /// Maximum perplexity increase allowed vs baseline (1.5 = 50% worse is acceptable)
+    max_perplexity_ratio: f32 = 1.5,
+    /// Absolute maximum perplexity threshold
+    absolute_perplexity_cap: f32 = 100.0,
+    /// Maximum loss delta allowed (new_loss - baseline_loss)
+    max_loss_delta: f32 = 0.5,
+    /// Minimum passing score (0.0 - 1.0)
+    min_passing_score: f32 = 0.7,
+    /// Maximum inference time per test (ms)
+    test_timeout_ms: u32 = 30000,
+    /// Keep failed adapters for debugging? (in .failed/ subdirectory)
+    keep_failed_adapters: bool = true,
+};
+
+/// Category of validation test
+pub const TestCategory = enum(u8) {
+    sanity, // Basic coherence (must pass or model is completely broken)
+    coherence, // Grammatical/semantic coherence
+    identity, // Does the model remember its persona?
+    domain, // Domain-specific capabilities (coding, etc.)
+};
+
+/// A single validation test case
+pub const ValidationTest = struct {
+    /// Unique identifier for logging
+    name: []const u8,
+    /// Category of test
+    category: TestCategory,
+    /// The prompt to send to the model
+    prompt: []const u8,
+    /// Expected patterns in the response (any match = good)
+    expected_patterns: []const []const u8,
+    /// Forbidden patterns (any match = bad, gibberish detection)
+    forbidden_patterns: []const []const u8,
+    /// Maximum allowed perplexity for this specific test
+    max_perplexity: ?f32,
+    /// Minimum response length (gibberish detector)
+    min_response_length: u32,
+    /// Weight for scoring (higher = more important)
+    weight: f32,
+};
+
+/// Result of a single test
+pub const TestResult = struct {
+    test_name: []const u8,
+    passed: bool,
+    score: f32, // 0.0 - 1.0
+    perplexity: f32, // Measured perplexity for this test
+    response_length: usize,
+    latency_ms: u64,
+    error_message: ?[]const u8,
+};
+
+/// Reason for validation failure
+pub const FailureReason = enum {
+    perplexity_too_high,
+    loss_delta_exceeded,
+    score_below_threshold,
+    gibberish_detected,
+    nan_weights_detected,
+    sanity_test_failed,
+    adapter_file_invalid,
+};
+
+/// Aggregate validation result
+pub const ValidationResult = struct {
+    /// Overall pass/fail
+    passed: bool,
+    /// Aggregate score (weighted average)
+    aggregate_score: f32,
+    /// Individual test results
+    test_results: []TestResult,
+    /// Metrics comparison
+    baseline_perplexity: f32,
+    new_adapter_perplexity: f32,
+    perplexity_ratio: f32,
+    loss_delta: f32,
+    /// Timing
+    total_validation_time_ms: u64,
+    /// Failure reason (if any)
+    failure_reason: ?FailureReason,
+
+    pub fn deinit(self: *ValidationResult, allocator: std.mem.Allocator) void {
+        allocator.free(self.test_results);
+    }
+};
+
+// =============================================================================
+// Default Test Set (Embedded)
+// =============================================================================
+
+/// Default embedded test set - covers sanity, coherence, identity, and domain
+pub const default_test_set = [_]ValidationTest{
+    // === SANITY TESTS (must pass or model is completely broken) ===
+    .{
+        .name = "sanity_hello",
+        .category = .sanity,
+        .prompt = "Hello",
+        .expected_patterns = &.{}, // Just needs coherent response
+        .forbidden_patterns = &.{ "[[[", "###", "??????", "undefined", "NaN" },
+        .max_perplexity = 50.0,
+        .min_response_length = 1,
+        .weight = 2.0,
+    },
+    .{
+        .name = "sanity_arithmetic",
+        .category = .sanity,
+        .prompt = "What is 2 + 2?",
+        .expected_patterns = &.{ "4", "four", "Four" },
+        .forbidden_patterns = &.{},
+        .max_perplexity = 30.0,
+        .min_response_length = 1,
+        .weight = 1.5,
+    },
+    .{
+        .name = "sanity_capital",
+        .category = .sanity,
+        .prompt = "The capital of France is",
+        .expected_patterns = &.{ "Paris", "paris" },
+        .forbidden_patterns = &.{},
+        .max_perplexity = 20.0,
+        .min_response_length = 1,
+        .weight = 1.5,
+    },
+
+    // === COHERENCE TESTS ===
+    .{
+        .name = "coherence_sentence",
+        .category = .coherence,
+        .prompt = "Write a single grammatically correct sentence about weather.",
+        .expected_patterns = &.{}, // Check for coherent output
+        .forbidden_patterns = &.{ "dkfjdk", "asdfasdf", "[UNK]", "####" },
+        .max_perplexity = 40.0,
+        .min_response_length = 10,
+        .weight = 1.0,
+    },
+
+    // === IDENTITY TESTS ===
+    .{
+        .name = "identity_assistant",
+        .category = .identity,
+        .prompt = "What are you?",
+        .expected_patterns = &.{ "assistant", "AI", "language model", "helpful", "model" },
+        .forbidden_patterns = &.{},
+        .max_perplexity = 40.0,
+        .min_response_length = 5,
+        .weight = 1.0,
+    },
+
+    // === DOMAIN TESTS (coding) ===
+    .{
+        .name = "domain_code",
+        .category = .domain,
+        .prompt = "Write a Python function that adds two numbers:",
+        .expected_patterns = &.{ "def", "return" },
+        .forbidden_patterns = &.{},
+        .max_perplexity = 30.0,
+        .min_response_length = 15,
+        .weight = 1.0,
+    },
+};
+
+// =============================================================================
+// Dream Validator
+// =============================================================================
+
+pub const DreamValidator = struct {
+    allocator: std.mem.Allocator,
+    config: ValidationConfig,
+    test_set: []const ValidationTest,
+    model: *const llama.Model,
+    baseline_perplexity: f32,
+
+    const Self = @This();
+
+    /// Initialize the dream validator
+    /// Computes baseline metrics using the model without any adapter
+    pub fn init(
+        allocator: std.mem.Allocator,
+        model: *const llama.Model,
+        config: ValidationConfig,
+    ) !Self {
+        // Use default test set
+        const test_set: []const ValidationTest = &default_test_set;
+
+        // Compute baseline perplexity (model without adapter)
+        // For now, use a reasonable default - actual computation would require inference
+        const baseline_perplexity: f32 = 15.0; // Typical for well-trained models
+
+        logger.info("Dream validator initialized with {d} tests", .{test_set.len});
+
+        return Self{
+            .allocator = allocator,
+            .config = config,
+            .test_set = test_set,
+            .model = model,
+            .baseline_perplexity = baseline_perplexity,
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        _ = self;
+        // Nothing to free - we use embedded test set
+    }
+
+    /// Validate a newly trained adapter
+    /// Returns validation result; adapter is NOT applied to model yet
+    pub fn validateAdapter(
+        self: *Self,
+        adapter_path: []const u8,
+    ) !ValidationResult {
+        const start_time = std.time.milliTimestamp();
+
+        // 1. Basic file checks
+        try self.checkAdapterFile(adapter_path);
+
+        // 2. Run test suite and collect results
+        var test_results = try self.allocator.alloc(TestResult, self.test_set.len);
+        errdefer self.allocator.free(test_results);
+
+        var total_score: f32 = 0.0;
+        var total_weight: f32 = 0.0;
+        var any_sanity_fail = false;
+        var gibberish_detected = false;
+
+        for (self.test_set, 0..) |test_case, i| {
+            test_results[i] = self.runSingleTest(test_case);
+
+            total_score += test_results[i].score * test_case.weight;
+            total_weight += test_case.weight;
+
+            // Sanity tests must pass
+            if (test_case.category == .sanity and !test_results[i].passed) {
+                any_sanity_fail = true;
+            }
+
+            // Check for gibberish
+            if (test_results[i].error_message != null and
+                std.mem.eql(u8, test_results[i].error_message.?, "gibberish"))
+            {
+                gibberish_detected = true;
+            }
+        }
+
+        const aggregate_score = if (total_weight > 0) total_score / total_weight else 0.0;
+
+        // 3. Estimate adapter perplexity (simplified - based on test scores)
+        // In production, this would compute actual perplexity
+        const estimated_perplexity = self.baseline_perplexity * (2.0 - aggregate_score);
+        const perplexity_ratio = estimated_perplexity / self.baseline_perplexity;
+
+        // 4. Determine pass/fail
+        var failure_reason: ?FailureReason = null;
+        var passed = true;
+
+        if (any_sanity_fail) {
+            passed = false;
+            failure_reason = .sanity_test_failed;
+        } else if (gibberish_detected) {
+            passed = false;
+            failure_reason = .gibberish_detected;
+        } else if (perplexity_ratio > self.config.max_perplexity_ratio) {
+            passed = false;
+            failure_reason = .perplexity_too_high;
+        } else if (estimated_perplexity > self.config.absolute_perplexity_cap) {
+            passed = false;
+            failure_reason = .perplexity_too_high;
+        } else if (aggregate_score < self.config.min_passing_score) {
+            passed = false;
+            failure_reason = .score_below_threshold;
+        }
+
+        const end_time = std.time.milliTimestamp();
+
+        return ValidationResult{
+            .passed = passed,
+            .aggregate_score = aggregate_score,
+            .test_results = test_results,
+            .baseline_perplexity = self.baseline_perplexity,
+            .new_adapter_perplexity = estimated_perplexity,
+            .perplexity_ratio = perplexity_ratio,
+            .loss_delta = (1.0 - aggregate_score) * 0.5, // Estimated loss delta
+            .total_validation_time_ms = @intCast(end_time - start_time),
+            .failure_reason = failure_reason,
+        };
+    }
+
+    /// Run a single validation test
+    fn runSingleTest(self: *Self, test_case: ValidationTest) TestResult {
+        const start_time = std.time.milliTimestamp();
+
+        // For now, simulate test execution with pattern-based validation
+        // In production, this would:
+        // 1. Load adapter into temporary context
+        // 2. Run inference with test_case.prompt
+        // 3. Evaluate response against patterns
+
+        // Use baseline perplexity as reference for simulated tests
+        const simulated_perplexity = self.baseline_perplexity * 0.9; // Simulated - slightly better
+
+        // Simulate a passing response for testing the infrastructure
+        const simulated_response = switch (test_case.category) {
+            .sanity => "Hello! How can I help you today?",
+            .coherence => "The weather today is sunny with clear skies.",
+            .identity => "I am an AI assistant designed to be helpful.",
+            .domain => "def add(a, b):\n    return a + b",
+        };
+
+        var score: f32 = 1.0;
+        var passed = true;
+        var error_message: ?[]const u8 = null;
+
+        // Check minimum length
+        if (simulated_response.len < test_case.min_response_length) {
+            score -= 0.3;
+            passed = false;
+        }
+
+        // Check expected patterns
+        if (test_case.expected_patterns.len > 0) {
+            var found_expected = false;
+            for (test_case.expected_patterns) |pattern| {
+                if (std.mem.indexOf(u8, simulated_response, pattern) != null) {
+                    found_expected = true;
+                    break;
+                }
+            }
+            if (!found_expected) {
+                score -= 0.3;
+                passed = false;
+            }
+        }
+
+        // Check forbidden patterns (gibberish detection)
+        for (test_case.forbidden_patterns) |pattern| {
+            if (std.mem.indexOf(u8, simulated_response, pattern) != null) {
+                score -= 0.5;
+                passed = false;
+                error_message = "gibberish";
+                break;
+            }
+        }
+
+        // Check for gibberish using heuristics
+        if (isGibberish(simulated_response)) {
+            score -= 0.5;
+            passed = false;
+            error_message = "gibberish";
+        }
+
+        // Check perplexity if max is specified
+        if (test_case.max_perplexity) |max_ppl| {
+            if (simulated_perplexity > max_ppl) {
+                score -= 0.2;
+                if (simulated_perplexity > max_ppl * 1.5) {
+                    passed = false;
+                }
+            }
+        }
+
+        const end_time = std.time.milliTimestamp();
+
+        return TestResult{
+            .test_name = test_case.name,
+            .passed = passed and score >= 0.5,
+            .score = @max(0.0, score),
+            .perplexity = simulated_perplexity,
+            .response_length = simulated_response.len,
+            .latency_ms = @intCast(end_time - start_time),
+            .error_message = error_message,
+        };
+    }
+
+    /// Check adapter file for basic validity
+    fn checkAdapterFile(self: *Self, path: []const u8) !void {
+        _ = self;
+
+        // Check file exists and get stats
+        const stat = std.fs.cwd().statFile(path) catch |err| {
+            if (err == error.FileNotFound) return error.AdapterNotFound;
+            return err;
+        };
+
+        // Check reasonable size (not empty, not too large)
+        if (stat.size == 0) return error.EmptyAdapter;
+        if (stat.size > 10 * 1024 * 1024 * 1024) return error.AdapterTooLarge; // 10GB
+
+        // Check file can be opened
+        const file = try std.fs.cwd().openFile(path, .{});
+        defer file.close();
+
+        // Check for GGUF magic bytes (first 4 bytes = "GGUF")
+        var magic: [4]u8 = undefined;
+        const bytes_read = try file.read(&magic);
+        if (bytes_read < 4) return error.InvalidAdapterFormat;
+
+        if (!std.mem.eql(u8, &magic, "GGUF")) {
+            // Might be a different format - warn but don't fail
+            logger.warn("Adapter file doesn't have GGUF magic bytes", .{});
+        }
+    }
+};
+
+// =============================================================================
+// Gibberish Detection
+// =============================================================================
+
+/// Detect if output is likely gibberish
+pub fn isGibberish(text: []const u8) bool {
+    if (text.len == 0) return true;
+
+    // Check for repetitive patterns
+    if (hasExcessiveRepetition(text)) return true;
+
+    // Check character distribution
+    var letter_count: usize = 0;
+    var symbol_count: usize = 0;
+    var space_count: usize = 0;
+    var control_count: usize = 0;
+
+    for (text) |c| {
+        if ((c >= 'a' and c <= 'z') or (c >= 'A' and c <= 'Z')) {
+            letter_count += 1;
+        } else if (c == ' ') {
+            space_count += 1;
+        } else if (c < 32) {
+            control_count += 1;
+        } else if (c > 126) {
+            symbol_count += 1;
+        }
+    }
+
+    // Gibberish if no letters at all
+    if (letter_count == 0 and text.len > 5) return true;
+
+    // Gibberish if too many control characters
+    if (control_count > text.len / 4) return true;
+
+    // Gibberish if too many non-ASCII symbols (likely encoding issues)
+    const symbol_ratio = @as(f32, @floatFromInt(symbol_count)) / @as(f32, @floatFromInt(text.len));
+    if (symbol_ratio > 0.3) return true;
+
+    // Gibberish if very long text with no spaces (likely no word boundaries)
+    const space_ratio = @as(f32, @floatFromInt(space_count)) / @as(f32, @floatFromInt(text.len));
+    if (text.len > 50 and space_ratio < 0.05) return true;
+
+    return false;
+}
+
+/// Check for excessive character/word repetition
+fn hasExcessiveRepetition(text: []const u8) bool {
+    if (text.len < 20) return false;
+
+    // Check for repeated sequences of 3+ characters appearing 5+ times
+    var i: usize = 0;
+    while (i + 3 <= text.len) : (i += 1) {
+        const pattern = text[i .. i + 3];
+        var count: usize = 0;
+
+        var j: usize = 0;
+        while (j + 3 <= text.len) : (j += 1) {
+            if (std.mem.eql(u8, text[j .. j + 3], pattern)) {
+                count += 1;
+            }
+        }
+
+        // If pattern appears more than 5 times (excluding common patterns)
+        if (count >= 5) {
+            // Allow common patterns like "the", "and", "ing"
+            const common_patterns = [_][]const u8{ "the", "and", "ing", "ion", "ent", "   " };
+            var is_common = false;
+            for (common_patterns) |common| {
+                if (std.mem.eql(u8, pattern, common)) {
+                    is_common = true;
+                    break;
+                }
+            }
+            if (!is_common) return true;
+        }
+    }
+
+    // Check for single character repetition (e.g., "aaaaaaa")
+    var repeat_count: usize = 1;
+    var prev_char: u8 = text[0];
+    for (text[1..]) |c| {
+        if (c == prev_char) {
+            repeat_count += 1;
+            if (repeat_count >= 5) return true;
+        } else {
+            repeat_count = 1;
+            prev_char = c;
+        }
+    }
+
+    return false;
+}
+
+// =============================================================================
+// Tests
+// =============================================================================
+
+test "gibberish detection - empty string" {
+    try std.testing.expect(isGibberish(""));
+}
+
+test "gibberish detection - excessive repetition" {
+    try std.testing.expect(isGibberish("aaaaaaaaaaaaaaaaaaaaa"));
+    try std.testing.expect(isGibberish("abcabcabcabcabcabcabcabc"));
+}
+
+test "gibberish detection - valid text" {
+    try std.testing.expect(!isGibberish("Hello, how are you today?"));
+    try std.testing.expect(!isGibberish("The quick brown fox jumps over the lazy dog."));
+    try std.testing.expect(!isGibberish("def add(a, b): return a + b"));
+}
+
+test "gibberish detection - no word boundaries" {
+    try std.testing.expect(isGibberish("thisisaverylongstringwithnospacesatallwhichshouldbedetectedasgibberish"));
+}
+
+test "ValidationConfig defaults" {
+    const config = ValidationConfig{};
+    try std.testing.expectEqual(@as(f32, 1.5), config.max_perplexity_ratio);
+    try std.testing.expectEqual(@as(f32, 0.7), config.min_passing_score);
+    try std.testing.expect(config.enabled);
+    try std.testing.expect(config.keep_failed_adapters);
+}
+
+test "default test set has expected tests" {
+    try std.testing.expect(default_test_set.len >= 6);
+
+    // Verify sanity tests exist
+    var sanity_count: usize = 0;
+    for (default_test_set) |t| {
+        if (t.category == .sanity) sanity_count += 1;
+    }
+    try std.testing.expect(sanity_count >= 3);
+}
+
+test "hasExcessiveRepetition" {
+    try std.testing.expect(hasExcessiveRepetition("aaaaaaaaaaaaaaaaaaaa"));
+    try std.testing.expect(!hasExcessiveRepetition("Hello world"));
+    try std.testing.expect(!hasExcessiveRepetition("The the the")); // "the" is common
+}

