+    /// Initialize dream validator (call after model is loaded)
+    pub fn initDreamValidator(self: *Hippocampus, model: *const @import("llama.zig").Model) !void {
+        if (self.dream_validator_instance != null) {
+            logger.debug("Dream validator already initialized", .{});
+            return;
+        }
+
+        self.dream_validator_instance = try self.allocator.create(DreamValidator);
+        errdefer {
+            self.allocator.destroy(self.dream_validator_instance.?);
+            self.dream_validator_instance = null;
+        }
+
+        self.dream_validator_instance.?.* = try DreamValidator.init(
+            self.allocator,
+            model,
+            self.validation_config,
+        );
+
+        logger.info("Dream validator initialized (baseline ppl: {d:.1})", .{
+            self.dream_validator_instance.?.baseline_perplexity,
+        });
+    }
+
+    /// Handle validation failure: archive bad adapter and track consecutive failures
+    fn handleValidationFailure(
+        self: *Hippocampus,
+        adapter_path: []const u8,
+        result: ?ValidationResult,
+    ) !void {
+        // 1. Archive failed adapter if configured to keep them
+        if (self.validation_config.keep_failed_adapters) {
+            const archive_path = try self.archiveFailedAdapter(adapter_path);
+            defer self.allocator.free(archive_path);
+            logger.info("Bad adapter archived to: {s}", .{archive_path});
+        } else {
+            // Delete the failed adapter
+            std.fs.cwd().deleteFile(adapter_path) catch |err| {
+                logger.warn("Failed to delete bad adapter: {}", .{err});
+            };
+        }
+
+        // 2. Log individual test results if available
+        if (result) |validation_result| {
+            if (validation_result.test_results.len > 0) {
+                logger.info("Validation test breakdown:", .{});
+                for (validation_result.test_results) |test_result| {
+                    const status = if (test_result.passed) "PASS" else "FAIL";
+                    logger.info("  [{s}] {s} (ppl: {d:.1})", .{
+                        status,
+                        test_result.test_name,
+                        test_result.perplexity,
+                    });
+                }
+            }
+        }
+
+        // 3. Increment consecutive failure counter
+        self.consecutive_validation_failures += 1;
+
+        // 4. Warn user if we're seeing repeated failures
+        if (self.consecutive_validation_failures >= 3) {
+            logger.err("WARNING: {d} consecutive validation failures!", .{
+                self.consecutive_validation_failures,
+            });
+            logger.err("Consider reviewing conversation quality or adjusting validation thresholds.", .{});
+        }
+
+        // Note: Events are NOT marked as consolidated
+        // They will be retried in the next sleep cycle
+        logger.info("Events NOT marked consolidated - will retry in next sleep cycle", .{});
+    }
+
+    /// Archive a failed adapter to ~/.cache/zell/lora/failed/
+    fn archiveFailedAdapter(self: *Hippocampus, adapter_path: []const u8) ![]u8 {
+        const home = std.posix.getenv("HOME") orelse return error.NoHomeDir;
+
+        // Create failed adapters directory
+        const failed_dir = try std.fmt.allocPrint(
+            self.allocator,
+            "{s}/.cache/zell/lora/failed",
+            .{home},
+        );
+        defer self.allocator.free(failed_dir);
+
+        try std.fs.cwd().makePath(failed_dir);
+
+        // Generate unique filename with timestamp
+        const timestamp = std.time.timestamp();
+        const basename = std.fs.path.basename(adapter_path);
+        const archive_path = try std.fmt.allocPrint(
+            self.allocator,
+            "{s}/{d}_{s}",
+            .{ failed_dir, timestamp, basename },
+        );
+        errdefer self.allocator.free(archive_path);
+
+        // Copy the file to archive location
+        const src_file = try std.fs.cwd().openFile(adapter_path, .{});
+        defer src_file.close();
+
+        const dst_file = try std.fs.cwd().createFile(archive_path, .{});
+        defer dst_file.close();
+
+        var buf: [8192]u8 = undefined;
+        while (true) {
+            const bytes_read = try src_file.read(&buf);
+            if (bytes_read == 0) break;
+            try dst_file.writeAll(buf[0..bytes_read]);
+        }
+
+        // Delete the original (we'll regenerate next sleep)
+        std.fs.cwd().deleteFile(adapter_path) catch |err| {
+            logger.warn("Failed to delete original adapter after archive: {}", .{err});
+        };
+
+        return archive_path;
+    }
+
+    /// Update validation configuration
+    pub fn setValidationConfig(self: *Hippocampus, config: ValidationConfig) void {
+        self.validation_config = config;
+        if (self.dream_validator_instance) |validator| {
+            validator.config = config;
+        }
+        logger.debug("Validation config updated (enabled: {})", .{config.enabled});
+    }
+
+    /// Get current validation statistics
+    pub fn getValidationStats(self: *const Hippocampus) struct {
+        enabled: bool,
+        consecutive_failures: u32,
+        validator_initialized: bool,
+    } {
+        return .{
+            .enabled = self.validation_config.enabled,
+            .consecutive_failures = self.consecutive_validation_failures,
+            .validator_initialized = self.dream_validator_instance != null,
+        };
+    }
 };
